## Teststruktur
Datei: app-mock-react/tests/push-consent.spec.ts

```typescript
import { test, expect } from '@playwright/test';
import { AuthServiceClient } from '../../e2e/helpers/client.ts';
import { createRegisteredDevice } from '../../e2e/helpers/fixtures.ts';

const client = new AuthServiceClient();

test.describe('Push Consent Flow', () => {
  test('device with binding shows consent screen when push consent request exists', async ({ page }) => {
    // 1. Gerät registrieren (via fixture helper)
    const { userId, deviceId, keys, cleanup } = await createRegisteredDevice(client);
    try {
      // 2. App-Login via API (biometric device flow) — holt OIDC tokens
      const loginRes = await client.startLogin({ deviceId });
      expect(loginRes.status).toBe(200);
      const { nonce, challenge } = loginRes.body as { nonce: string; challenge: string };

      const { signChallenge } = await import('../../e2e/helpers/crypto.ts');
      const signature = signChallenge(keys.privateKeyPem, challenge);

      const verifyRes = await client.verifyChallenge({ nonce, signature });
      expect(verifyRes.status).toBe(200);
      const tokens = verifyRes.body as { access_token: string };

      // 3. Push-Consent-Anfrage via API erstellen (simulates Keycloak SPI call)
      const consentRes = await client.createPushConsentRequest({
        userId,
        sessionId: 'test-session-123',
        ttlSeconds: 120,
      });
      expect(consentRes.status).toBe(201);
      const { requestId } = consentRes.body as { requestId: string };

      // 4. App navigieren und ConsentScreen aufrufen
      await page.goto('/');
      // (In real flow: App receives tokens, polls /push-consent/pending, shows ConsentScreen)
      // For E2E: inject tokens into localStorage und navigate to consent screen via URL param
      // OR: use page.evaluate() to set app state

      // Simpler approach: test the API calls directly
      // GET /push-consent/pending → prüfen ob Anfrage zurückkommt
      const pendingRes = await client.getPendingConsent(tokens.access_token);
      expect(pendingRes.status).toBe(200);
      expect(pendingRes.body).toMatchObject({ requestId, userId });

      // 5. Zustimmung erteilen
      const resolveRes = await client.resolveConsent(tokens.access_token, requestId, true);
      expect(resolveRes.status).toBe(200);

      // 6. Status prüfen (Keycloak-SPI-Perspektive)
      const statusRes = await client.getPushConsentStatus('test-session-123');
      expect(statusRes.status).toBe(200);
      expect(statusRes.body).toMatchObject({ status: 'APPROVED' });

    } finally {
      await cleanup();
    }
  });

  test('consent request denied returns DENIED status', async ({ page }) => {
    const { userId, deviceId, keys, cleanup } = await createRegisteredDevice(client);
    try {
      const loginRes = await client.startLogin({ deviceId });
      const { nonce, challenge } = loginRes.body as { nonce: string; challenge: string };
      const { signChallenge } = await import('../../e2e/helpers/crypto.ts');
      const signature = signChallenge(keys.privateKeyPem, challenge);
      const verifyRes = await client.verifyChallenge({ nonce, signature });
      const tokens = verifyRes.body as { access_token: string };

      const consentRes = await client.createPushConsentRequest({
        userId,
        sessionId: 'test-session-deny-456',
        ttlSeconds: 120,
      });
      const { requestId } = consentRes.body as { requestId: string };

      // Deny consent
      await client.resolveConsent(tokens.access_token, requestId, false);

      const statusRes = await client.getPushConsentStatus('test-session-deny-456');
      expect(statusRes.body).toMatchObject({ status: 'DENIED' });
    } finally {
      await cleanup();
    }
  });

  test('expired consent request returns no pending request', async () => {
    const { userId, deviceId, keys, cleanup } = await createRegisteredDevice(client);
    try {
      const loginRes = await client.startLogin({ deviceId });
      const { nonce, challenge } = loginRes.body as { nonce: string; challenge: string };
      const { signChallenge } = await import('../../e2e/helpers/crypto.ts');
      const signature = signChallenge(keys.privateKeyPem, challenge);
      const verifyRes = await client.verifyChallenge({ nonce, signature });
      const tokens = verifyRes.body as { access_token: string };

      // Create consent request with ttl=1 second
      await client.createPushConsentRequest({ userId, sessionId: 'test-expire-789', ttlSeconds: 1 });

      // Wait 2 seconds for expiry
      await new Promise(r => setTimeout(r, 2000));

      // Should return 204 (no pending)
      const pendingRes = await client.getPendingConsent(tokens.access_token);
      expect(pendingRes.status).toBe(204);
    } finally {
      await cleanup();
    }
  });
});
```

