```java
package dev.authsandbox.authservice.service;

import dev.authsandbox.authservice.dto.*;
import dev.authsandbox.authservice.entity.PushConsentRequest;
import dev.authsandbox.authservice.repository.DeviceRepository;
import dev.authsandbox.authservice.repository.PushConsentRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;
import java.util.NoSuchElementException;
import java.util.Optional;
import java.util.UUID;

@Service
@RequiredArgsConstructor
@Slf4j
public class PushConsentService {

    private final PushConsentRepository pushConsentRepository;
    private final DeviceRepository deviceRepository;

    /** Erstellt eine neue Consent-Anfrage (aufgerufen von Keycloak-SPI via HTTP Basic) */
    @Transactional
    public CreatePushConsentResponse createRequest(CreatePushConsentRequest req) {
        // Alte PENDING-Anfragen für diesen User löschen (cleanup)
        pushConsentRepository.findFirstByUserIdAndStatusOrderByCreatedAtDesc(
            req.userId(), PushConsentRequest.Status.PENDING)
            .ifPresent(old -> {
                old.setStatus(PushConsentRequest.Status.DENIED);
                pushConsentRepository.save(old);
            });

        OffsetDateTime expiresAt = OffsetDateTime.now().plusSeconds(req.ttlSeconds());
        PushConsentRequest entity = PushConsentRequest.builder()
            .userId(req.userId())
            .sessionId(req.sessionId())
            .status(PushConsentRequest.Status.PENDING)
            .expiresAt(expiresAt)
            .build();
        pushConsentRepository.save(entity);
        log.info("Created push consent request {} for user {}", entity.getId(), req.userId());
        return new CreatePushConsentResponse(entity.getId(), expiresAt);
    }

    /** App fragt ab: hat mein User eine ausstehende Consent-Anfrage? */
    @Transactional(readOnly = true)
    public Optional<PushConsentPendingResponse> getPending(String userId) {
        return pushConsentRepository.findFirstByUserIdAndStatusOrderByCreatedAtDesc(
            userId, PushConsentRequest.Status.PENDING)
            .filter(r -> r.getExpiresAt().isAfter(OffsetDateTime.now()))
            .map(r -> new PushConsentPendingResponse(r.getId(), r.getUserId(), r.getExpiresAt()));
    }

    /** App erteilt oder verweigert Zustimmung */
    @Transactional
    public ResolvePushConsentResponse resolve(UUID requestId, String userId, boolean approved) {
        PushConsentRequest request = pushConsentRepository.findById(requestId)
            .orElseThrow(() -> new NoSuchElementException("Consent request not found: " + requestId));

        if (!request.getUserId().equals(userId)) {
            throw new IllegalArgumentException("Not authorized to resolve this request");
        }
        if (request.getStatus() != PushConsentRequest.Status.PENDING) {
            throw new IllegalStateException("Request already resolved: " + request.getStatus());
        }
        if (request.getExpiresAt().isBefore(OffsetDateTime.now())) {
            throw new IllegalStateException("Request expired");
        }

        request.setStatus(approved ? PushConsentRequest.Status.APPROVED : PushConsentRequest.Status.DENIED);
        pushConsentRepository.save(request);
        log.info("Resolved push consent request {} as {}", requestId, request.getStatus());
        return new ResolvePushConsentResponse(request.getStatus().name());
    }

    /** Keycloak-SPI fragt Status ab (per sessionId) */
    @Transactional(readOnly = true)
    public PushConsentStatusResponse getStatus(String sessionId) {
        PushConsentRequest request = pushConsentRepository.findBySessionId(sessionId)
            .orElseThrow(() -> new NoSuchElementException("No consent request for session: " + sessionId));

        // Wenn noch PENDING und abgelaufen → als DENIED behandeln
        if (request.getStatus() == PushConsentRequest.Status.PENDING &&
            request.getExpiresAt().isBefore(OffsetDateTime.now())) {
            return new PushConsentStatusResponse("DENIED");
        }
        return new PushConsentStatusResponse(request.getStatus().name());
    }

    /** Cleanup: abgelaufene Anfragen löschen (alle 5 Minuten) */
    @Scheduled(fixedDelay = 300_000)
    @Transactional
    public void cleanupExpired() {
        pushConsentRepository.deleteExpired(OffsetDateTime.now());
    }
}
```

